children.value:
var(--a)
				color-mix(in hsl, var(--b) var(--c, var(--d00000000000000000000000000)), transparent),
			var(--e)
				color-mix(in hsl, var(--f) var(--g, var(--h00000000000000000000000000)), transparent)

content.styles:
div {
	/* 101 chars - we break to stay within 100, Prettier tolerates the overage */
	box-shadow:
		var(--a)
			color-mix(in hsl, var(--b) var(--c, var(--d00000000000000000000000000)), transparent),
		var(--e)
			color-mix(in hsl, var(--f) var(--g, var(--h00000000000000000000000000)), transparent);
}
